        @mcp.tool()
        async def email_extract_attachments(input_filename: str) -> dict:
            """
            Extract all attachments from an email file stored on the server.
        
            IMPORTANT:
            * All *_filename parameters accept ONLY the bare filename (e.g. 'message.eml') — no path, no directory, no drive letter, no slash.
            * The file MUST already exist in the server's ASPOSE_INPUT_DIR folder before calling this tool.
            * Do NOT ask the user to upload a file — files are pre‑placed in the server folder by the user.
            * Output files are written to ASPOSE_OUTPUT_DIR (falls back to ASPOSE_INPUT_DIR if unset).
        
            Args:
                input_filename: bare filename of the email file containing attachments, e.g. 'mail.eml'.
        
            Returns:
                dict: {
                    "status": "success" | "error",
                    "message": str,
                    "saved_files": list[str],          # names of the extracted attachment files
                    "output_filename": str            # empty because multiple files are written
                }
        
            Raises:
                FileNotFoundError: if the input email file cannot be located.
                PermissionError: if the server cannot write to the output directory.
                Exception: for any unexpected Aspose errors.
        
            Example:
                result = await email_extract_attachments("example.eml")
                # result["saved_files"] might be ["photo.jpg", "doc.pdf"]
            """
            import os
            import logging
            from pathlib import Path
        
            logger = logging.getLogger(__name__)
        
            # ---------- Resolve input ----------
            input_filename = Path(input_filename.strip().replace('\x00', '')).name
            _input_dir = os.environ.get("ASPOSE_INPUT_DIR", "").strip()
            if not _input_dir:
                raise FileNotFoundError(
                    f"File not found: {input_filename} — ASPOSE_INPUT_DIR environment variable is not configured."
                )
            resolved_input = str(Path(_input_dir) / input_filename)
            if not Path(resolved_input).is_file():
                raise FileNotFoundError(f"File not found: {input_filename} (ASPOSE_INPUT_DIR={_input_dir})")
        
            # ---------- Resolve output directory ----------
            _out_dir = os.environ.get("ASPOSE_OUTPUT_DIR", "").strip() or os.environ.get("ASPOSE_INPUT_DIR", "").strip()
            try:
                Path(_out_dir).mkdir(parents=True, exist_ok=True)
            except Exception as exc:
                logger.error("Failed to create output directory: %s", exc)
                return {"status": "error", "message": f"Cannot create output directory: {exc}", "saved_files": [], "output_filename": ""}
        
            # ---------- Extract attachments ----------
            try:
                import aspose.email as ae  # lazy import as required
                msg = ae.MailMessage.load(resolved_input)  # load the email
        
                saved_files = []
                for att in msg.attachments:
                    att_path = str(Path(_out_dir) / att.name)
                    att.save(att_path)
                    saved_files.append(att.name)
        
                if not saved_files:
                    return {
                        "status": "success",
                        "message": "No attachments found in the email.",
                        "saved_files": [],
                        "output_filename": ""
                    }
        
                return {
                    "status": "success",
                    "message": f"Extracted {len(saved_files)} attachment(s).",
                    "saved_files": saved_files,
                    "output_filename": ""  # multiple files; placeholder per spec
                }
        
            except Exception as exc:  # catch Aspose and any other errors
                logger.exception("Error extracting attachments from %s", input_filename)
                return {"status": "error", "message": str(exc), "saved_files": [], "output_filename": ""}

