        @mcp.tool()
        async def email_extract_from_pst(
            input_filename: str,
            folder_name: str | None = None,
            output_filename: str | None = None,
        ) -> dict:
            """
            Extract all messages from a PST file and save them as individual EML files.
        
            IMPORTANT:
            * All *_filename parameters accept ONLY the bare filename (e.g. 'archive.pst') — no path, no directory, no drive letter, no slash.
            * The file MUST already exist in the server's ASPOSE_INPUT_DIR folder before calling this tool.
            * Do NOT ask the user to upload a file — files are pre‑placed in the server folder by the user.
            * Output files are written to ASPOSE_OUTPUT_DIR (falls back to ASPOSE_INPUT_DIR if unset).
        
            Args:
                input_filename: PST file to process (bare filename, must exist in ASPOSE_INPUT_DIR).
                folder_name: Name of the folder inside the PST to extract from; if omitted the root folder is used.
                output_filename: Base name for output files; each message will be saved as <subject>.eml if not provided.
                                 If supplied, files are named `<output_filename>_N.eml` where N is a sequential index.
        
            Returns:
                dict: {
                    "status": "success" | "error",
                    "message": description of the operation,
                    "created_files": list of EML filenames written,
                    "output_filename": str (the supplied base name or empty string)
                }
        
            Raises:
                FileNotFoundError: If the input PST file cannot be located.
                Exception: Propagates unexpected errors from Aspose with an error status.
        
            Example:
                result = await email_extract_from_pst(
                    input_filename="myarchive.pst",
                    folder_name="Inbox",
                    output_filename="msg"
                )
                # result["created_files"] might be ["msg_1.eml", "msg_2.eml", ...]
            """
            import os
            import logging
            from pathlib import Path
        
            # Resolve input file (ASPOSE_INPUT_DIR)
            input_filename = Path(input_filename.strip().replace("\x00", "")).name
            _input_dir = os.environ.get("ASPOSE_INPUT_DIR", "").strip()
            if not _input_dir:
                raise FileNotFoundError(
                    f"File not found: {input_filename} — ASPOSE_INPUT_DIR environment variable is not configured."
                )
            resolved_input = str(Path(_input_dir) / input_filename)
            if not Path(resolved_input).is_file():
                raise FileNotFoundError(
                    f"File not found: {input_filename} (ASPOSE_INPUT_DIR={_input_dir})"
                )
        
            # Resolve output directory (ASPOSE_OUTPUT_DIR fallback to INPUT)
            _out_dir = os.environ.get("ASPOSE_OUTPUT_DIR", "").strip() or os.environ.get("ASPOSE_INPUT_DIR", "").strip()
            Path(_out_dir).mkdir(parents=True, exist_ok=True)
        
            # Normalise optional output base name
            if output_filename is not None:
                output_filename = Path(output_filename.strip().replace("\x00", "")).name
                # Strip any extension – we will add our own .eml suffix
                output_base = output_filename.rsplit(".", 1)[0]
            else:
                output_base = None
        
            created_files: list[str] = []
            logger = logging.getLogger(__name__)
        
            try:
                import aspose.email as ae
        
                # Load PST
                pst = ae.storage.pst.PersonalStorage.from_file(resolved_input)
        
                # Choose folder
                if folder_name:
                    try:
                        folder = pst.root_folder.get_sub_folder(folder_name)
                    except Exception as exc:
                        raise FileNotFoundError(f"Folder '{folder_name}' not found in PST.") from exc
                else:
                    folder = pst.root_folder
        
                # Enumerate messages
                for idx, msg_info in enumerate(folder.enumerate_messages(), start=1):
                    try:
                        msg = pst.extract_message(msg_info)
        
                        # Determine filename
                        if output_base:
                            eml_name = f"{output_base}_{idx}.eml"
                        else:
                            subject = msg_info.subject or f"message_{idx}"
                            # Sanitize subject to a safe filename
                            safe_subject = "".join(
                                c for c in subject if c.isalnum() or c in (" ", "_", "-")
                            ).strip()
                            if not safe_subject:
                                safe_subject = f"message_{idx}"
                            eml_name = f"{safe_subject}.eml"
        
                        resolved_eml = str(Path(_out_dir) / eml_name)
                        msg.save(resolved_eml, ae.SaveOptions.default_eml)
                        created_files.append(eml_name)
                    except Exception as inner_exc:
                        logger.error(
                            "Failed to extract/save message %s from PST: %s", getattr(msg_info, "subject", "unknown"), inner_exc
                        )
                        continue
        
                return {
                    "status": "success",
                    "message": f"Extracted {len(created_files)} message(s) from PST.",
                    "created_files": created_files,
                    "output_filename": output_base or "",
                }
        
            except Exception as exc:
                logger.exception("Error processing PST file %s", input_filename)
                return {"status": "error", "message": str(exc), "created_files": [], "output_filename": output_base or ""}

        @mcp.tool()
        async def email_read_mbox(
            input_filename: str,
            max_count: int | None = None,
        ) -> dict:
            """
            Read subjects from an MBOX file.
        
            IMPORTANT: All *_filename parameters accept ONLY the bare filename (e.g. 'archive.mbox') —
            no path, no directory, no drive letter, no slash.
            The file MUST already exist in the server's ASPOSE_INPUT_DIR folder.
            Do NOT ask the user to upload a file — files are pre-placed in that folder.
            Output files are written to the same folder; returned output_filename is the bare name only.
        
            Args:
                input_filename (str): Bare filename of the MBOX file to read. Must exist in ASPOSE_INPUT_DIR.
                max_count (int | None, optional): Maximum number of messages to read; if omitted all messages are read.
        
            Returns:
                dict: {
                    "status": "success" | "error",
                    "message": str,
                    "subjects": list[str]
                }
        
            Raises:
                FileNotFoundError: If the input file does not exist.
                Exception: For any other error while reading the MBOX.
        
            Example:
                >>> result = await email_read_mbox("archive.mbox", max_count=10)
                >>> result["subjects"]
            """
            import logging
            from pathlib import Path
            from mcp_server.path_utils import get_safe_path, temp_output_path  # temp_output_path imported per project standards
        
            # Sanitize and resolve the input filename safely
            input_filename = Path(input_filename.strip().replace('\x00', '')).name
            resolved_input = get_safe_path(input_filename)
            if not Path(resolved_input).is_file():
                raise FileNotFoundError(f"File not found: {input_filename}")
        
            # Import Aspose after the file existence check
            import aspose.email as ae
        
            logger = logging.getLogger(__name__)
        
            subjects: list[str] = []
            reader = None
            try:
                reader = ae.storage.mbox.MboxrdStorageReader(resolved_input, False)
                count = 0
                msg = reader.read_next_message()
                while msg is not None:
                    subjects.append(msg.subject or "")
                    count += 1
                    if max_count is not None and count >= max_count:
                        break
                    msg = reader.read_next_message()
                return {
                    "status": "success",
                    "message": f"Read {len(subjects)} message(s) from {input_filename}.",
                    "subjects": subjects,
                }
            except Exception as exc:  # pragma: no cover
                logger.exception("Error reading MBOX file")
                return {"status": "error", "message": str(exc), "subjects": []}
            finally:
                if reader is not None:
                    try:
                        reader.dispose()
                    except Exception as dispose_exc:  # pragma: no cover
                        logger.debug("Failed to dispose MboxrdStorageReader: %s", dispose_exc)

