        @mcp.tool()
        async def email_save_message(
            input_filename: str,
            output_filename: str | None,
            save_option: str,
        ) -> dict:
            """
            Convert and save an email message to a different format.
        
            IMPORTANT: All *_filename parameters accept ONLY the bare filename (e.g. 'scan.jpg') —
            no path, no directory, no drive letter, no slash.
            The file MUST already exist in the server's ASPOSE_INPUT_DIR folder.
            Do NOT ask the user to upload a file — files are pre‑placed in that folder.
            Output files are written to the same folder; returned output_filename is the bare name only.
        
            Args:
                input_filename: Bare filename of the source email (e.g. 'message.eml') — must already exist in ASPOSE_INPUT_DIR.
                output_filename: Optional bare filename for the converted email. If omitted, a name is generated from the input.
                save_option: One of "msg", "eml", "mhtml", "html" indicating the desired output format.
        
            Returns:
                dict: {
                    "status": "success" | "error",
                    "message": str,
                    "output_filename": str   # bare name of the written file (only on success)
                }
        
            Example:
                >>> result = await email_save_message(
                ...     input_filename="original.eml",
                ...     output_filename=None,
                ...     save_option="msg",
                ... )
                >>> result["status"]
                "success"
                >>> result["output_filename"]
                "original.msg"
        
            Raises:
                FileNotFoundError: If the input file cannot be located.
                ValueError: If an unsupported save_option is supplied.
                Exception: Any unexpected error from Aspose.Email.
            """
            import logging
            from pathlib import Path
            from mcp_server.path_utils import get_safe_path, temp_output_path
        
            logger = logging.getLogger(__name__)
        
            # ---------- Resolve and validate input ----------
            input_filename = Path(input_filename.strip().replace('\x00', '')).name
            resolved_input = get_safe_path(input_filename)
            if not Path(resolved_input).is_file():
                raise FileNotFoundError(f"File not found: {input_filename}")
        
            # ---------- Determine output filename ----------
            # Mapping of save_option to Aspose save options and file extension
            option_map = {
                "msg": ("default_msg_unicode", "msg"),
                "eml": ("default_eml", "eml"),
                "mhtml": ("default_mhtml", "mhtml"),
                "html": ("default_html", "html"),
            }
        
            if save_option not in option_map:
                raise ValueError(
                    f"Invalid save_option '{save_option}'. Must be one of: {', '.join(option_map)}"
                )
        
            save_opt_name, ext = option_map[save_option]
        
            if output_filename is not None:
                output_filename = Path(output_filename.strip().replace('\x00', '')).name
                output_basename = output_filename
                resolved_output = temp_output_path(Path(output_basename).stem, f".{ext}")
            else:
                output_basename = f"{Path(input_filename).stem}.{ext}"
                resolved_output = temp_output_path(Path(output_basename).stem, f".{ext}")
        
            # ---------- Import Aspose after validation ----------
            import aspose.email as ae
        
            # Retrieve the actual Aspose SaveOptions object
            save_opt_obj = getattr(ae.SaveOptions, save_opt_name)
        
            try:
                # Load the email
                msg = ae.MailMessage.load(resolved_input)
        
                # Save using the selected format
                msg.save(str(resolved_output), save_opt_obj)
        
                return {
                    "status": "success",
                    "message": f"Email saved as {save_option.upper()}.",
                    "output_filename": output_basename,
                }
            except Exception as exc:  # pragma: no cover
                logger.exception("Failed to save email")
                return {"status": "error", "message": str(exc)}

